foreach ($cat in $cats.Keys) {
  $lines = @()
  foreach ($file in $cats[$cat]) {
    $name = [System.IO.Path]::GetFileNameWithoutExtension($file)
    $folderEncoded = [uri]::EscapeUriString($cat)
    $fileEncoded = [uri]::EscapeUriString($file)
    $nameEscaped = $name -replace "'", "&apos;"
    $waMsg = "Hola!%20Consulto%20por%20" + [uri]::EscapeUriString($name)
    $card = '<div class="product-card"><img class="product-card-img" src="productos/' + $folderEncoded + '/' + $fileEncoded + '" alt="' + $name + '"><div class="product-card-name">' + $name + '</div><div class="product-card-price"></div><div class="product-card-actions"><div class="qty-controls"><button class="qty-btn qty-minus" onclick="event.stopPropagation(); updateQty(this, -1)">&#8722;</button><span class="qty-value">1</span><button class="qty-btn qty-plus" onclick="event.stopPropagation(); updateQty(this, 1)">+</button></div><button class="btn-add-cart" onclick="addToCart(this, ' + "'" + $nameEscaped + "'" + ')"><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3"><path d="M12 5v14M5 12h14"/></svg> Agregar al carrito</button></div><a href="https://wa.me/5493534012349?text=' + $waMsg + '" class="product-card-wa" target="_blank" rel="noopener">' + $svgWA + ' Consultar</a></div>'
    $lines += $card
  }
  $html = $lines -join "`n"
  $safeName = $cat -replace '[^\w\s-]', '_'
  # Write as UTF8 without BOM
  $utf8 = [System.Text.UTF8Encoding]::new($false)
  [System.IO.File]::WriteAllText([System.IO.Path]::Combine($outDir2, $safeName + ".txt"), $html, $utf8)
  Write-Host "Wrote $safeName.txt"
}
